const { SlashCommandBuilder } = require('discord.js');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('ban')
    .setDescription('Bans a user')
    .addIntegerOption((option) =>
      option.setName('duration').setDescription('How long to ban for (in seconds)')
    )
    .addIntegerOption((option) =>
      option.setName('amount').setDescription('Number of users to ban')
    )
    .addIntegerOption((option) =>
      option.setName('threshold').setDescription('Number of arguments to trigger ban')
    ),
  interactions: [
    {
      name: 'ban',
      type: 'slashCommand',
      options: [
        {
          name: 'duration',
          type: 'integer',
        },
        {
          name: 'amount',
          type: 'integer',
        },
        {
          name: 'threshold',
          type: 'integer',
        },
      ],
      functionality: (interaction) => {
        if (interaction.options.getInteger('duration') && interaction.options.getInteger('amount')) {
          const duration = interaction.options.getInteger('duration') * 60;
          const users = interaction.options.getInteger('amount');
          interaction.reply(`Banning ${users} users for ${duration / 60} minutes.`);
          interaction.reply.defer(duration, {
            content: `Banning ${users} users for ${duration / 60} minutes.`,
          });
        } else if (interaction.options.getInteger('threshold')) {
          interaction.reply(`Banning all users if ${interaction.options.getInteger('threshold')} arguments are provided.`);
          interaction.reply.defer(1, {
            content: `Banning all users if ${interaction.options.getInteger('threshold')} arguments are provided.`,
          });
        } else {
          interaction.reply('Please provide a duration and an amount to ban users.');
        }
      },
    },
  ],
};
```
